def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):

    def distance(pos1, pos2):
        return np.linalg.norm(pos1 - pos2)

    def penalty(time, window):
        if time < window[0]:
            return window[0] - time
        elif time > window[1]:
            return time - window[1]
        else:
            return 0

    best_node = None
    best_time = float('inf')

    for i, customer_pos in enumerate(unvisited_customers):
        for j, truck_pos in enumerate(all_truck_pos):
            travel_time = distance(truck_pos, customer_pos) / truck_speed
            arrival_time = current_time + travel_time
            window_penalty = penalty(arrival_time, time_windows[i])
            last_truck_time = max(arrival_time, current_time)

            if last_truck_time + window_penalty < best_time:
                best_node = i
                best_time = last_truck_time + window_penalty

    return best_node
